lessons.example:
def divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return 'cannot divide by zero'

print(divide(10, 2))   # 5.0
print(divide(10, 0))   # cannot divide by zero

def convert(text):
    try:
        return int(text)
    except ValueError:
        return None

print(convert('42'))   # 42
print(convert('abc'))  # None (doesn't break the program)

def valid_age(age):
    if age < 0:
        raise ValueError('age cannot be negative')
    return age

try:
    valid_age(-5)
except ValueError as error:
    print(f'error: {error}')
finally:
    print('validation complete')

